namespace sv_3e87e68dc9ea4364a64f13c513f7e6ff.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_3e87e68dc9ea4364a64f13c513f7e6ff.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-name"># @Channel.Name</div>
    <div class="channel-description">@TruncatedDescription</div>
    @if (Channel.UnreadCount > 0)
    {
        <span class="unread-badge">@Channel.UnreadCount</span>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<Channel> OnSelected { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40 ? Channel.Description[..40] + "…" : Channel.Description;

    private async Task OnClick() => await OnSelected.InvokeAsync(Channel);
}

@using sv_3e87e68dc9ea4364a64f13c513f7e6ff.Services

<div class="channel-sidebar">
    <h3 class="sidebar-title">Channels</h3>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = new();
    [Parameter] public int? ActiveChannelId { get; set; }
    [Parameter] public EventCallback<Channel> OnChannelSelected { get; set; }
}

@using sv_3e87e68dc9ea4364a64f13c513f7e6ff.Services

<div class="message-bubble" @onmouseenter="() => showActions = true" @onmouseleave="() => showActions = false">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" @onclick="() => HandleReaction(reaction.Emoji)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <div class="thread-link" @onclick="HandleOpenThread">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </div>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="HandleOpenThread" title="Reply">💬</button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="React">😀</button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in commonEmojis)
            {
                <span class="emoji-option" @onclick="() => HandleReaction(emoji)">@emoji</span>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;
    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private async Task HandleOpenThread() => await OnOpenThread.InvokeAsync(Message.Id);

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task HandleReaction(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }
}

@using sv_3e87e68dc9ea4364a64f13c513f7e6ff.Services

<div class="message-list" @onscroll="HandleScroll">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages...</div>
    }

    @foreach (var message in Messages)
    {
        <MessageBubble Message="message"
                       ReplyCount="GetReplyCount(message.Id)"
                       OnOpenThread="OnOpenThread"
                       OnReact="OnReact" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = new();
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task HandleScroll(EventArgs e)
    {
        // Scroll-to-top triggers loading more messages
        await OnLoadMore.InvokeAsync();
    }
}

@using sv_3e87e68dc9ea4364a64f13c513f7e6ff.Services

<div class="message-panel">
    <div class="panel-header">
        <h2 class="channel-header-name"># @ChannelName</h2>
        <p class="channel-header-description">@ChannelDescription</p>
    </div>

    <MessageList Messages="Messages"
                 ThreadReplyCounts="ThreadReplyCounts"
                 IsLoadingMore="IsLoadingMore"
                 OnLoadMore="OnLoadMore"
                 OnOpenThread="OnOpenThread"
                 OnReact="OnReact" />

    <MessageInput Placeholder="@($"Message #{ChannelName}")"
                  ButtonText="Send"
                  OnSend="OnSendMessage" />
</div>

@code {
    [Parameter] public string ChannelName { get; set; } = string.Empty;
    [Parameter] public string ChannelDescription { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = new();
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
}

@using sv_3e87e68dc9ea4364a64f13c513f7e6ff.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <span class="message-author">@RootMessage.Author</span>
            <p class="message-content">@RootMessage.Content</p>
        </div>
    }

    <div class="thread-replies">
        @foreach (var reply in Replies)
        {
            <div class="thread-reply">
                <div class="message-header">
                    <span class="message-author">@reply.Author</span>
                    <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                </div>
                <div class="message-content">@reply.Content</div>
            </div>
        }
    </div>

    <MessageInput Placeholder="Reply in thread..."
                  ButtonText="Reply"
                  OnSend="OnSendReply" />
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter, EditorRequired] public List<Message> Replies { get; set; } = new();
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@page "/chat"
@using sv_3e87e68dc9ea4364a64f13c513f7e6ff.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<div class="chat-layout">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="selectedChannel?.Id"
                    OnChannelSelected="HandleChannelSelected" />

    <div class="chat-main @(threadOpen ? "with-thread" : "")">
        <MessagePanel ChannelName="@(selectedChannel?.Name ?? "")"
                      ChannelDescription="@(selectedChannel?.Description ?? "")"
                      Messages="messages"
                      ThreadReplyCounts="threadReplyCounts"
                      IsLoadingMore="isLoadingMore"
                      OnLoadMore="HandleLoadMore"
                      OnOpenThread="HandleOpenThread"
                      OnReact="HandleReact"
                      OnSendMessage="HandleSendMessage" />
    </div>

    @if (threadOpen)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="HandleCloseThread"
                     OnSendReply="HandleSendReply" />
    }
</div>

@code {
    private List<Channel> channels = new();
    private Channel? selectedChannel;
    private List<Message> messages = new();
    private Dictionary<int, int> threadReplyCounts = new();
    private bool isLoadingMore;

    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = new();

    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await HandleChannelSelected(channels[0]);
        }
    }

    private async Task HandleChannelSelected(Channel channel)
    {
        selectedChannel = channel;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        await ChatService.MarkChannelReadAsync(channel.Id);
        threadOpen = false;
        threadRootMessage = null;
        threadReplies = new();
        await BuildThreadReplyCounts();
    }

    private async Task HandleLoadMore()
    {
        if (isLoadingMore || selectedChannel is null) return;
        isLoadingMore = true;

        var olderMessages = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, PageSize);
        if (olderMessages.Count > 0)
        {
            messages.InsertRange(0, olderMessages);
        }

        isLoadingMore = false;
    }

    private async Task HandleOpenThread(int messageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(messageId);
        threadOpen = true;
    }

    private async Task HandleCloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies = new();
        await Task.CompletedTask;
    }

    private async Task HandleReact((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);
        // Refresh the message list to show updated reactions
        if (selectedChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, messages.Count);
        }
    }

    private async Task HandleSendMessage(string content)
    {
        if (selectedChannel is null) return;
        var newMessage = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(newMessage);
    }

    private async Task HandleSendReply(string content)
    {
        if (selectedChannel is null || threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update reply count
        threadReplyCounts[threadRootMessage.Id] = threadReplies.Count;
    }

    private async Task BuildThreadReplyCounts()
    {
        threadReplyCounts = new();
        // Count messages that are replies (have ReplyToId) grouped by their root
        foreach (var msg in messages.Where(m => m.ReplyToId.HasValue))
        {
            var rootId = msg.ReplyToId!.Value;
            threadReplyCounts[rootId] = threadReplyCounts.GetValueOrDefault(rootId) + 1;
        }
