                      ChannelDescription="@(selectedChannel?.Description ?? "")"
                      Messages="messages"
                      ThreadReplyCounts="threadReplyCounts"
                      IsLoadingMore="isLoadingMore"
                      OnLoadMore="HandleLoadMore"
                      OnOpenThread="HandleOpenThread"
                      OnReact="HandleReact"
                      OnSendMessage="HandleSendMessage" />
    </div>

    @if (threadOpen)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="HandleCloseThread"
                     OnSendReply="HandleSendReply" />
    }
</div>

@code {
    private List<Channel> channels = new();
    private Channel? selectedChannel;
    private List<Message> messages = new();
    private Dictionary<int, int> threadReplyCounts = new();
    private bool isLoadingMore;

    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = new();

    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await HandleChannelSelected(channels[0]);
        }
    }

    private async Task HandleChannelSelected(Channel channel)
    {
        selectedChannel = channel;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        await ChatService.MarkChannelReadAsync(channel.Id);
        threadOpen = false;
        threadRootMessage = null;
        threadReplies = new();
        await BuildThreadReplyCounts();
    }

    private async Task HandleLoadMore()
    {
        if (isLoadingMore || selectedChannel is null) return;
        isLoadingMore = true;

        var olderMessages = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, PageSize);
        if (olderMessages.Count > 0)
        {
            messages.InsertRange(0, olderMessages);
        }

        isLoadingMore = false;
    }

    private async Task HandleOpenThread(int messageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(messageId);
        threadOpen = true;
    }

    private async Task HandleCloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies = new();
        await Task.CompletedTask;
    }

    private async Task HandleReact((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);
        // Refresh the message list to show updated reactions
        if (selectedChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, messages.Count);
        }
    }

    private async Task HandleSendMessage(string content)
    {
        if (selectedChannel is null) return;
        var newMessage = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(newMessage);
    }

    private async Task HandleSendReply(string content)
    {
        if (selectedChannel is null || threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update reply count
        threadReplyCounts[threadRootMessage.Id] = threadReplies.Count;
    }

    private async Task BuildThreadReplyCounts()
    {
        threadReplyCounts = new();
        // Count messages that are replies (have ReplyToId) grouped by their root
        foreach (var msg in messages.Where(m => m.ReplyToId.HasValue))
        {
            var rootId = msg.ReplyToId!.Value;
            threadReplyCounts[rootId] = threadReplyCounts.GetValueOrDefault(rootId) + 1;
        }
        await Task.CompletedTask;
    }
}
"}

