toolArgs.file_text:
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

/* Channel Sidebar */
.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2c2f33;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #202225;
}

.sidebar-title {
    padding: 16px;
    margin: 0;
    font-size: 1rem;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: #8e9297;
    border-bottom: 1px solid #202225;
}

.channel-list {
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 10px 16px;
    cursor: pointer;
    display: flex;
    flex-direction: column;
    gap: 2px;
    position: relative;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #34373c;
}

.channel-item.active {
    background: #393c43;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

.channel-description {
    font-size: 0.75rem;
    color: #72767d;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    position: absolute;
    top: 12px;
    right: 12px;
    background: #ed4245;
    color: white;
    border-radius: 10px;
    padding: 1px 6px;
    font-size: 0.7rem;
    font-weight: 700;
}

/* Main Chat Area */
.chat-main {
    flex: 1;
    display: flex;
    min-width: 0;
}

.chat-main.with-thread {
    flex: 0 0 55%;
}

.message-panel {
    display: flex;
    flex-direction: column;
    width: 100%;
    background: #36393f;
    color: #dcddde;
}

.panel-header {
    padding: 12px 20px;
    border-bottom: 1px solid #202225;
    flex-shrink: 0;
}

.channel-header-name {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

.channel-header-description {
    margin: 4px 0 0;
    font-size: 0.8rem;
    color: #8e9297;
}

/* Message List */
.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 20px;
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.loading-indicator {
    text-align: center;
    padding: 8px;
    color: #8e9297;
    font-size: 0.8rem;
}

/* Message Bubble */
.message-bubble {
    padding: 8px 12px;
    border-radius: 4px;
    position: relative;
    transition: background 0.1s;
}

.message-bubble:hover {
    background: #32353b;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
}

.message-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.9rem;
}

.message-time {
    font-size: 0.7rem;
    color: #72767d;
}

.message-content {
    margin-top: 4px;
    font-size: 0.9rem;
    line-height: 1.4;
    word-wrap: break-word;
}

/* Reactions */
.message-reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    background: #2f3136;
    border: 1px solid #4f545c;
    border-radius: 4px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #4f545c;
}

/* Thread Link */
.thread-link {
    margin-top: 4px;
    font-size: 0.8rem;
    color: #00aff4;
    cursor: pointer;
}

.thread-link:hover {
    text-decoration: underline;
}

/* Message Actions */
.message-actions {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #2f3136;
    border: 1px solid #4f545c;
    border-radius: 4px;
    padding: 2px;
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 3px;
    font-size: 0.9rem;
}

.action-btn:hover {
    background: #4f545c;
}

/* Emoji Picker */
.emoji-picker {
    display: flex;
    gap: 4px;
    background: #2f3136;
    border: 1px solid #4f545c;
    border-radius: 4px;
    padding: 6px;
    margin-top: 4px;
    width: fit-content;
}

.emoji-option {
    cursor: pointer;
    padding: 4px;
    border-radius: 3px;
    font-size: 1.1rem;
}

.emoji-option:hover {
    background: #4f545c;
}

/* Message Input */
.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid #202225;
    flex-shrink: 0;
}

.message-textarea {
    flex: 1;
    background: #40444b;
    border: none;
    border-radius: 8px;
    padding: 10px 14px;
    color: #dcddde;
    font-size: 0.9rem;
    resize: none;
    min-height: 40px;
    max-height: 120px;
    font-family: inherit;
}

.message-textarea::placeholder {
    color: #72767d;
}

.message-textarea:focus {
    outline: none;
}

.send-btn {
    background: #5865f2;
    color: white;
    border: none;
    border-radius: 8px;
    padding: 10px 20px;
    font-weight: 600;
    cursor: pointer;
    align-self: flex-end;
    transition: background 0.15s;
}

.send-btn:hover:not(:disabled) {
    background: #4752c4;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* Thread Panel */
.thread-panel {
    width: 25%;
    min-width: 250px;
    background: #2f3136;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    border-left: 1px solid #202225;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #202225;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    color: #fff;
}

.close-btn {
    background: none;
    border: none;
    color: #8e9297;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 3px;
}

.close-btn:hover {
    background: #4f545c;
    color: #fff;
}

.thread-root-message {
    padding: 12px 16px;
    border-bottom: 1px solid #202225;
    background: #36393f;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 12px 16px;
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.thread-reply {
    padding: 8px;
    border-radius: 4px;
}

.thread-reply:hover {
    background: #36393f;
}

