+.thread-link:hover {
+    text-decoration: underline;
+}
+
+/* Message Actions */
+.message-actions {
+    position: absolute;
+    top: -8px;
+    right: 8px;
+    display: flex;
+    gap: 2px;
+    background: #2f3136;
+    border: 1px solid #4f545c;
+    border-radius: 4px;
+    padding: 2px;
+}
+
+.action-btn {
+    background: none;
+    border: none;
+    cursor: pointer;
+    padding: 4px 8px;
+    border-radius: 3px;
+    font-size: 0.9rem;
+}
+
+.action-btn:hover {
+    background: #4f545c;
+}
+
+/* Emoji Picker */
+.emoji-picker {
+    display: flex;
+    gap: 4px;
+    background: #2f3136;
+    border: 1px solid #4f545c;
+    border-radius: 4px;
+    padding: 6px;
+    margin-top: 4px;
+    width: fit-content;
+}
+
+.emoji-option {
+    cursor: pointer;
+    padding: 4px;
+    border-radius: 3px;
+    font-size: 1.1rem;
+}
+
+.emoji-option:hover {
+    background: #4f545c;
+}
+
+/* Message Input */
+.message-input-area {
+    display: flex;
+    gap: 8px;
+    padding: 12px 20px;
+    border-top: 1px solid #202225;
+    flex-shrink: 0;
+}
+
+.message-textarea {
+    flex: 1;
+    background: #40444b;
+    border: none;
+    border-radius: 8px;
+    padding: 10px 14px;
+    color: #dcddde;
+    font-size: 0.9rem;
+    resize: none;
+    min-height: 40px;
+    max-height: 120px;
+    font-family: inherit;
+}
+
+.message-textarea::placeholder {
+    color: #72767d;
+}
+
+.message-textarea:focus {
+    outline: none;
+}
+
+.send-btn {
+    background: #5865f2;
+    color: white;
+    border: none;
+    border-radius: 8px;
+    padding: 10px 20px;
+    font-weight: 600;
+    cursor: pointer;
+    align-self: flex-end;
+    transition: background 0.15s;
+}
+
+.send-btn:hover:not(:disabled) {
+    background: #4752c4;
+}
+
+.send-btn:disabled {
+    opacity: 0.5;
+    cursor: not-allowed;
+}
+
+/* Thread Panel */
+.thread-panel {
+    width: 25%;
+    min-width: 250px;
+    background: #2f3136;
+    color: #dcddde;
+    display: flex;
+    flex-direction: column;
+    border-left: 1px solid #202225;
+}
+
+.thread-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    padding: 12px 16px;
+    border-bottom: 1px solid #202225;
+}
+
+.thread-header h3 {
+    margin: 0;
+    font-size: 1rem;
+    color: #fff;
+}
+
+.close-btn {
+    background: none;
+    border: none;
+    color: #8e9297;
+    font-size: 1.2rem;
+    cursor: pointer;
+    padding: 4px 8px;
+    border-radius: 3px;
+}
+
+.close-btn:hover {
+    background: #4f545c;
+    color: #fff;
+}
+
+.thread-root-message {
+    padding: 12px 16px;
+    border-bottom: 1px solid #202225;
+    background: #36393f;
+}
+
+.thread-replies {
+    flex: 1;
+    overflow-y: auto;
+    padding: 12px 16px;
+    display: flex;
+    flex-direction: column;
+    gap: 8px;
+}
+
+.thread-reply {
+    padding: 8px;
+    border-radius: 4px;
+}
+
+.thread-reply:hover {
+    background: #36393f;
+}
+

